# [doc = " **Render the inspectability signal** at a given DX consumption tier (RFC-0034 §7)."] # [doc = ""] # [doc = " The [`ModeSignal`] was already captured by [`generate_mode_signal`] — this function only"] # [doc = " controls *how verbose* the output is. Calling this with a higher tier on an existing"] # [doc = " `ModeSignal` surfaces more of the already-captured history, **with no re-run or mode switch**."] # [doc = ""] # [doc = " | Tier | Output |"] # [doc = " |------|--------|"] # [doc = " | [`Lean`](ConsumptionTier::Lean) | one compact line — `certification: fast  [default]` |"] # [doc = " | [`Medium`](ConsumptionTier::Medium) | adds the depth rank |"] # [doc = " | [`Full`](ConsumptionTier::Full) | adds the generation≠consumption split note |"] # [doc = ""] # [doc = " The `Lean` output is identical to [`explain_mode`] applied to the same [`ResolvedMode`] —"] # [doc = " that function is the mode-EXPLAIN floor (always-available, mode-independent, §13d)."] # [must_use] pub fn render_mode_signal (signal : & ModeSignal , tier : ConsumptionTier) -> String { let src = signal . resolved . source . map_or ("default" , CertScope :: label) ; let mode_word = cert_mode_word (signal . resolved . mode) ; match tier { ConsumptionTier :: Lean => { format ! ("certification: {mode_word}  [{src}]") } ConsumptionTier :: Medium => { format ! ("certification: {mode_word}  [{src}]  (depth {})" , signal . depth) } ConsumptionTier :: Full => { format ! ("certification: {mode_word}  [{src}]  (depth {})\n  \
                 signal: generated (always-on, RFC-0034 §7); consumption tier: full\n  \
                 note: dial consumption up any time — the history is already captured" , signal . depth ,) } } }

# [doc = " Parse a dependency `hash` into a typed [`mycelium_core::ContentHash`] (DN-40 A3 — parse,"] # [doc = " don't validate). The value must be a string and a well-formed content address (`<algo>:<digest>`,"] # [doc = " `ContentHash::parse`); for the kernel's fixed algorithm (`blake3`, M-103) the digest must"] # [doc = " additionally be a real digest — exactly **64 lowercase hex** (what `blake3::hash().to_hex()`"] # [doc = " emits), so a shape-valid-but-bogus stub like `\"blake3:abc\"` is rejected, not just `\"blake3:\"`."] # [doc = " A malformed pin is an **explicit** `ManifestError` naming the offending dependency and the bad"] # [doc = " value (never silent — G2); a well-formed address is `Exact` by construction."] fn as_content_hash (val : & Val , dep_name : & str , line : u32 ,) -> Result < mycelium_core :: ContentHash , ManifestError > { let s = as_str (val , "hash" , line) ? ; let malformed = | detail : & str | ManifestError { line , message : format ! ("dependency `{dep_name}` has a malformed content-address `hash` {s:?} — {detail}; the \
             pin is identity-bearing (ADR-003) and is checked, never accepted as free text \
             (DN-40 A3 / G2)") , } ; let h = mycelium_core :: ContentHash :: parse (& s) . ok_or_else (| | malformed ("expected `<algo>:<digest>` (e.g. `blake3:<64-hex>`)")) ? ; if ! h . has_well_formed_digest () { return Err (malformed ("a `blake3` digest must be exactly 64 lowercase hex characters (M-103)" ,)) ; } Ok (h) }

# [doc = " The `EXPLAIN` of a resolved header — every field with its value and source, so nothing about the"] # [doc = " metadata is ambient (G2). Stable, line-oriented, deterministic."] # [must_use] pub fn explain (r : & ResolvedHeader) -> String { let mut out = String :: new () ; let name = r . name . as_ref () . map_or_else (| | "(bare nodule)" . to_owned () , | segs | segs . join (".")) ; out . push_str (& format ! ("nodule: {name}
")) ; let mut row = | field : & str , value : Option < String > , origin : Option < Origin > | match value { Some (v) => out . push_str (& format ! ("  {field}: {v}  [{}]
" , origin . map_or ("local" , Origin :: label))) , None => out . push_str (& format ! ("  {field}: —  [unset]
")) , } ; row ("version" , r . version . as_ref () . map (| x | x . value . clone ()) , r . version . as_ref () . map (| x | x . origin) ,) ; row ("license" , r . license . as_ref () . map (| x | x . value . clone ()) , r . license . as_ref () . map (| x | x . origin) ,) ; row ("authors" , r . authors . as_ref () . map (| x | x . value . join (", ")) , r . authors . as_ref () . map (| x | x . origin) ,) ; row ("since" , r . since . as_ref () . map (| x | x . value . clone ()) , r . since . as_ref () . map (| x | x . origin) ,) ; row ("repository" , r . repository . as_ref () . map (| x | x . value . clone ()) , r . repository . as_ref () . map (| x | x . origin) ,) ; row ("keywords" , r . keywords . as_ref () . map (| x | x . value . join (", ")) , r . keywords . as_ref () . map (| x | x . origin) ,) ; row ("updated" , r . updated . clone () , r . updated . as_ref () . map (| _ | Origin :: Local) ,) ; row ("summary" , r . summary . clone () , r . summary . as_ref () . map (| _ | Origin :: Local) ,) ; let dep = r . deprecated . as_ref () . map (| d | match d { Deprecated :: Flag (b) => b . to_string () , Deprecated :: Reason (s) => s . clone () , }) ; row ("deprecated" , dep , r . deprecated . as_ref () . map (| _ | Origin :: Local) ,) ; let cert_src = r . certification . source . map_or ("default" , CertScope :: label) ; out . push_str (& format ! ("  certification: {}  [{cert_src}]
" , cert_mode_word (r . certification . mode))) ; out }
